request.query:
BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?reqName ?state ?stateName WHERE {
  ?pkg vocab:NamedElement_name "APS%20Interface%20Requirements" .
  ?pkg vocab:Package_packagedElement+ ?req .
  ?req rdf:type vocab:tmt%20requirement .
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
  OPTIONAL {
    ?req vocab:acceptance%20state ?state .
    OPTIONAL { ?state vocab:NamedElement_name ?stateName . }
  }
}
LIMIT 25

BASE <http://api.koneksys.com/cameo/>
PREFIX vocab: <http://api.koneksys.com/cameo/vocab/>
PREFIX rdf:   <http://www.w3.org/1999/02/22-rdf-syntax-ns#>
SELECT ?req ?reqName ?type WHERE {
  ?req rdf:type ?type .
  FILTER(?type IN (vocab:tmt%20requirement, vocab:requirement))
  OPTIONAL { ?req vocab:NamedElement_name ?reqName . }
  FILTER(
    (BOUND(?reqName) && CONTAINS(LCASE(STR(?reqName)), LCASE("aps")) && CONTAINS(LCASE(STR(?reqName)), LCASE("interface")))
  )
}
LIMIT 25
